insert into bank_questions (question_key, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('3-4-recruitment-and-selection:tips:798c922f', '3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tips', 'mcq', 1, '{"readingTitle": "Common Error — Don''t just describe the method — give the advantage", "reading": "<p>Examiners do NOT award marks for describing what a method is (e.g. \"an interview is where you ask candidates questions\"). You must state the <strong>advantage for the business</strong> of using that method.</p>\n<p>Also avoid generic phrases like \"it helps find the best person for the job\" — this is the purpose of all selection methods and earns no marks.</p>", "question": "Why do examiners award no marks for a statement like ''an interview is where you ask candidates questions''?", "options": ["It just describes the method, not a business advantage", "Because interviews are not a valid selection method", "Because it exceeds the word limit for the question", "Because it should be written in the case study instead"]}'::jsonb, '{"answer": 0, "explain": "The card warns that examiners do not award marks for describing what a method is — students must state the advantage for the business of using it."}'::jsonb),
('3-4-recruitment-and-selection:tips:697a353c', '3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tips', 'mcq', 1, '{"readingTitle": "Key Fact — Internal vs External — Know the Data", "reading": "<p>From the BFF (Best Foot Forward) case study — always reference specific data when it is given:</p>\n<ul>\n<li>Internal recruitment cost: £500 vs External: £2,500 (£2,000 cheaper)</li>\n<li>Internal induction cost: £200 vs External: £1,500 (£1,300 cheaper)</li>\n<li>Total saving from internal: £3,300</li>\n<li>Days to fill the job: Internal 20 days vs External 60 days (3× faster)</li>\n</ul>\n<p>Using these numbers in analysis earns application marks.</p>", "question": "In the BFF case study data on this card, how much cheaper is internal recruitment cost compared to external?", "options": ["£2,000 cheaper", "£1,300 cheaper", "£3,300 cheaper", "£500 cheaper"]}'::jsonb, '{"answer": 0, "explain": "The card states internal recruitment cost is £500 versus external at £2,500 — a difference of £2,000."}'::jsonb),
('3-4-recruitment-and-selection:fib:574b9d7a', '3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'fib', 'fib', 4, '{"question": "Recruitment and _____ are very important to businesses. The _____ in a business make it successful or not. Recruiting new staff is _____. If good staff are not recruited by firms, money spent on the recruitment process is _____.", "blankOptions": {"B1": ["selection", "harder", "simple", "slower"], "B2": ["application form", "letter", "workers", "interview"], "B3": ["already working", "earned", "expensive", "person specification"], "B4": ["quicker", "person specification", "planning", "wasted"]}}'::jsonb, '{"blanks": {"B1": "selection", "B2": "workers", "B3": "expensive", "B4": "wasted"}}'::jsonb),
('3-4-recruitment-and-selection:fib:a8ee35e1', '3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'fib', 'fib', 4, '{"question": "Internal recruitment is when a job vacancy is filled by someone _____ in the business. External recruitment is when someone from _____ the business is appointed. Internal recruitment is usually _____ and _____ than external recruitment.", "blankOptions": {"B1": ["wasted", "self-employed", "slower", "already working"], "B2": ["expensive", "advertising", "outside", "earned"], "B3": ["invested", "cheaper", "person specification", "self-employed"], "B4": ["noticeboard", "letter", "quicker", "job description"]}}'::jsonb, '{"blanks": {"B1": "already working", "B2": "outside", "B3": "cheaper", "B4": "quicker"}}'::jsonb),
('3-4-recruitment-and-selection:fib:0e1f225b', '3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'fib', 'fib', 4, '{"question": "A _____ lists the main duties and tasks of the worker. A _____ lists the qualities, qualifications and experience needed. Letters of application are good for showing a person''s _____ skills. A _____ is used at the final stage of selection and allows the interviewer to judge the candidate''s personality and communication.", "blankOptions": {"B1": ["motivation", "above", "job description", "cheaper"], "B2": ["person specification", "earned", "products", "wasted"], "B3": ["communication", "application form", "riskier", "newly graduated"], "B4": ["riskier", "saved", "harder", "interview"]}}'::jsonb, '{"blanks": {"B1": "job description", "B2": "person specification", "B3": "communication", "B4": "interview"}}'::jsonb),
('3-4-recruitment-and-selection:match:949b6c21', '3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Recruitment”?", "options": ["The process of choosing between applicants for a job", "A list of the main duties, tasks and responsibilities of a worker", "A list of the qualities, qualifications and knowledge a person should have to do a particular job", "The process of finding people to work in a new or established business"]}'::jsonb, '{"answer": 3, "explain": "“Recruitment” means: The process of finding people to work in a new or established business"}'::jsonb),
('3-4-recruitment-and-selection:match:f66da66a', '3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Selection”?", "options": ["A list of the main duties, tasks and responsibilities of a worker", "A list of the qualities, qualifications and knowledge a person should have to do a particular job", "When a business recruits skilled workers because it is short of them", "The process of choosing between applicants for a job"]}'::jsonb, '{"answer": 3, "explain": "“Selection” means: The process of choosing between applicants for a job"}'::jsonb),
('3-4-recruitment-and-selection:match:28162b5b', '3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Job description”?", "options": ["A list of the main duties, tasks and responsibilities of a worker", "A list of the qualities, qualifications and knowledge a person should have to do a particular job", "When a business recruits skilled workers because it is short of them", "Training to introduce a new worker to the business, place of work and fellow workers"]}'::jsonb, '{"answer": 0, "explain": "“Job description” means: A list of the main duties, tasks and responsibilities of a worker"}'::jsonb),
('3-4-recruitment-and-selection:match:84ae7d44', '3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Person specification”?", "options": ["When a business recruits skilled workers because it is short of them", "A list of the qualities, qualifications and knowledge a person should have to do a particular job", "Training to introduce a new worker to the business, place of work and fellow workers", "A document on which the applicant outlines their personal details, experience and skills"]}'::jsonb, '{"answer": 1, "explain": "“Person specification” means: A list of the qualities, qualifications and knowledge a person should have to do a particular job"}'::jsonb),
('3-4-recruitment-and-selection:match:a84c246c', '3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Skills gap”?", "options": ["Training to introduce a new worker to the business, place of work and fellow workers", "A document on which the applicant outlines their personal details, experience and skills", "A form specifying what information the business needs; all applicants fill in the same form", "When a business recruits skilled workers because it is short of them"]}'::jsonb, '{"answer": 3, "explain": "“Skills gap” means: When a business recruits skilled workers because it is short of them"}'::jsonb),
('3-4-recruitment-and-selection:match:2f217555', '3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Induction training”?", "options": ["A document on which the applicant outlines their personal details, experience and skills", "A form specifying what information the business needs; all applicants fill in the same form", "Training to introduce a new worker to the business, place of work and fellow workers", "The process of finding people to work in a new or established business"]}'::jsonb, '{"answer": 2, "explain": "“Induction training” means: Training to introduce a new worker to the business, place of work and fellow workers"}'::jsonb),
('3-4-recruitment-and-selection:match:a9044611', '3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “CV”?", "options": ["A form specifying what information the business needs; all applicants fill in the same form", "The process of finding people to work in a new or established business", "A document on which the applicant outlines their personal details, experience and skills", "The process of choosing between applicants for a job"]}'::jsonb, '{"answer": 2, "explain": "“CV” means: A document on which the applicant outlines their personal details, experience and skills"}'::jsonb),
('3-4-recruitment-and-selection:match:d79c7019', '3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Application form”?", "options": ["The process of finding people to work in a new or established business", "A form specifying what information the business needs; all applicants fill in the same form", "The process of choosing between applicants for a job", "A list of the main duties, tasks and responsibilities of a worker"]}'::jsonb, '{"answer": 1, "explain": "“Application form” means: A form specifying what information the business needs; all applicants fill in the same form"}'::jsonb),
('3-5-motivation-and-retention:exam:9ec15024', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'exam', 'mcq', 1, '{"num": "Q2", "question": "What is a financial method of motivation that a restaurant manager may use?", "options": ["An award scheme for the chefs to develop low cost meals", "Introduce profit sharing for the chefs", "Make staff pay for any glasses or plates they break", "Praise staff who suggest how the restaurant could save money"], "hint": "Think about which option involves a direct payment of money to workers.", "starter": "The answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Introduce profit sharing for the chefs</h5>\n<ul>\n  <li><strong>A — Wrong:</strong> An award scheme is a non-financial method of motivation — it involves recognition, not money.</li>\n  <li><strong>B — Correct:</strong> Profit sharing is a financial method — it involves paying workers a proportion of the business''s profits.</li>\n  <li><strong>C — Wrong:</strong> Making staff pay for breakages is a penalty/deduction, not a motivational method at all.</li>\n  <li><strong>D — Wrong:</strong> Praise is a non-financial method of motivation — it involves verbal/written recognition, not money.</li>\n</ul></div>", "modelAnswer": "B — Introduce profit sharing for the chefs."}'::jsonb),
('3-5-motivation-and-retention:exam:ab6871f7', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'exam', 'mcq', 1, '{"num": "Q3", "question": "What is a non-financial method of motivation that a manufacturer of handmade wooden toys could use?", "options": ["Giving production operatives a bonus for every 1000 toys made", "Increasing the rate of pay for workers in the dusty woodcutting shed", "Praising the workers who take the greatest care when painting the designs", "Providing free private medical insurance to all workers"], "hint": "Non-financial methods do NOT involve any payment of money or cash benefits. Which option involves recognition rather than pay?", "starter": "The answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Praising the workers who take the greatest care when painting the designs</h5>\n<ul>\n  <li><strong>A — Wrong:</strong> A bonus is a financial method — it is an additional cash payment for meeting a target.</li>\n  <li><strong>B — Wrong:</strong> Increasing the rate of pay is a financial method — it involves paying workers more money per hour.</li>\n  <li><strong>C — Correct:</strong> Praise is a non-financial method — it involves recognising and complimenting good work with no money exchanged.</li>\n  <li><strong>D — Wrong:</strong> Private medical insurance is a fringe benefit — a financial method, as it has a monetary value to the worker.</li>\n</ul></div>", "modelAnswer": "C — Praising the workers who take the greatest care when painting the designs."}'::jsonb),
('3-5-motivation-and-retention:exam:f4699117', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'exam', 'mcq', 1, '{"num": "Q4", "question": "Employee retention:", "options": ["extends the working hours of employees", "leads to higher recruitment costs", "minimises time spent selecting new workers", "reduces discrimination in the workplace"], "hint": "Retention means workers STAY at a business. Think about what happens to recruitment if you don''t need to replace staff.", "starter": "The answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — minimises time spent selecting new workers</h5>\n<ul>\n  <li><strong>A — Wrong:</strong> Retention refers to workers staying — it does not extend working hours.</li>\n  <li><strong>B — Wrong:</strong> High retention REDUCES recruitment costs, not increases them. This is the opposite of the correct answer.</li>\n  <li><strong>C — Correct:</strong> When workers stay (high retention), the business does not need to advertise and recruit as often, saving time spent on selection.</li>\n  <li><strong>D — Wrong:</strong> Retention has nothing to do with discrimination policies in the workplace.</li>\n</ul>\n<p><strong>Examiner''s Comment:</strong> Responses were evenly split across the three wrong options — candidates must know the precise definition of retention to avoid confusion with related HR terms.</p></div>", "modelAnswer": "C — minimises time spent selecting new workers."}'::jsonb),
('3-5-motivation-and-retention:exam:d00c7560', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'exam', 'mcq', 1, '{"num": "Q5", "question": "A supermarket chain is receiving an increasing number of complaints about the poor attitude of its sales assistants, especially when the stores are busy. What would help to deal with this problem?", "options": ["Employ fewer sales assistants at each of its stores", "Find ways to increase employee motivation at each of its stores", "Limit the number of customers that can enter each store at any one time", "Reduce the holiday entitlement of any employee that is rude to a customer"], "hint": "Poor attitude from staff is usually a symptom of something deeper. What business concept directly links to how hard and willingly workers perform?", "starter": "The answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Find ways to increase employee motivation at each of its stores</h5>\n<ul>\n  <li><strong>A — Wrong:</strong> Fewer staff would make the pressure worse when stores are busy, increasing complaints rather than reducing them.</li>\n  <li><strong>B — Correct:</strong> Poor staff attitude is a symptom of low motivation. Improving motivation directly encourages staff to provide better customer service, especially under pressure.</li>\n  <li><strong>C — Wrong:</strong> Limiting customer numbers would reduce revenue and damage the business — it doesn''t address the root cause.</li>\n  <li><strong>D — Wrong:</strong> Reducing holiday entitlement is a punitive measure and would likely worsen morale and motivation, making the problem worse.</li>\n</ul></div>", "modelAnswer": "B — Find ways to increase employee motivation at each of its stores."}'::jsonb),
('3-5-motivation-and-retention:exam:83aba31c', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'exam', 'mcq', 1, '{"num": "Q6", "question": "A business has introduced a bonus scheme, based on production targets, to help motivate its staff. Which of the following statements would NOT be true?", "options": ["The bonus scheme is a form of performance-related pay", "The bonus scheme will increase business costs", "Unrealistic targets may lead to lower levels of motivation", "Workers who do not reach the target will have their basic pay reduced"], "hint": "Read the question carefully — it asks which statement is NOT true. A bonus is an addition to pay, not a reduction of it.", "starter": "The answer is D because..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Workers who do not reach the target will have their basic pay reduced</h5>\n<ul>\n  <li><strong>A — True (not the answer):</strong> Bonuses are triggered by performance — they are a form of performance-related pay.</li>\n  <li><strong>B — True (not the answer):</strong> Paying bonuses adds to the business''s total wage costs.</li>\n  <li><strong>C — True (not the answer):</strong> If targets are unrealistically high, workers give up rather than try — the bonus demotivates instead of motivating.</li>\n  <li><strong>D — NOT True (correct answer):</strong> A bonus scheme does not reduce basic pay for those who miss targets. Basic pay remains the same — workers simply do not receive the additional bonus payment.</li>\n</ul></div>", "modelAnswer": "D — Workers who do not reach the target will have their basic pay reduced."}'::jsonb),
('3-5-motivation-and-retention:exam:46c2ba76', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'exam', 'mcq', 1, '{"num": "Q7", "question": "Xaio and Zhou own a building firm that employs 50 workers. Xaio and Zhou are concerned about the costs of recruitment. They are constantly having to advertise for replacement workers. Which of the following would help Xaio and Zhou deal with this problem?", "options": ["Decrease the hourly rate paid to the workers", "Find ways to increase employee retention", "Give the workers fewer fringe benefits", "Obtain additional finance from the bank"], "hint": "The problem is that workers keep leaving. What is the business concept that means keeping workers in the business for longer?", "starter": "The answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Find ways to increase employee retention</h5>\n<ul>\n  <li><strong>A — Wrong:</strong> Decreasing pay would make the problem worse — workers would be even more likely to leave for better-paid roles elsewhere.</li>\n  <li><strong>B — Correct:</strong> If workers stay longer (high retention), Xaio and Zhou would not need to constantly advertise for replacements — directly reducing recruitment costs.</li>\n  <li><strong>C — Wrong:</strong> Reducing fringe benefits would decrease motivation and increase turnover, making the recruitment problem worse.</li>\n  <li><strong>D — Wrong:</strong> Additional finance doesn''t address the root problem of workers leaving — it might help pay for more recruitment but doesn''t fix retention.</li>\n</ul></div>", "modelAnswer": "B — Find ways to increase employee retention."}'::jsonb),
('3-5-motivation-and-retention:exam:85fbcb40', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'exam', 'mcq', 1, '{"num": "Q10", "question": "A jet ski retailer with limited funds has a problem with the motivation levels of its 25 sales assistants. Which one of the following methods should the jet ski retailer use to improve the sales assistants'' motivation levels?", "options": ["Increase the sales assistants'' pay rate by £3 per hour", "Offer sales assistants a bonus of £500 for each jet ski sold", "Reduce the number of fringe benefits given to employees", "Set up a ''seller of the month'' award scheme"], "hint": "The key constraint is LIMITED FUNDS. Which option improves motivation without spending significant money?", "starter": "The answer is D because..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Set up a ''seller of the month'' award scheme</h5>\n<ul>\n  <li><strong>A — Wrong:</strong> A £3 per hour pay rise for 25 staff would be expensive — with limited funds, this may not be affordable.</li>\n  <li><strong>B — Wrong:</strong> A £500 bonus per jet ski sold could be very costly. Jet skis are expensive items — if sales are high, this could massively increase the wage bill.</li>\n  <li><strong>C — Wrong:</strong> Reducing fringe benefits would decrease motivation and morale — the opposite of what is needed.</li>\n  <li><strong>D — Correct:</strong> An award scheme is a non-financial method that costs very little but provides recognition and boosts morale — the ideal solution for a business with limited funds.</li>\n</ul></div>", "modelAnswer": "D — Set up a ''seller of the month'' award scheme."}'::jsonb),
('3-5-motivation-and-retention:exam:177ea7c3', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'exam', 'mcq', 1, '{"num": "Q14", "question": "Which one of the following is NOT a benefit to a business of improving employee retention?", "options": ["Cost saving", "Less time spent on recruitment", "Lower selling price", "Reduced need for training"], "hint": "Think carefully — retention means keeping workers longer. Three options are genuine benefits. One is completely unrelated to whether staff stay or leave.", "starter": "The answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Lower selling price</h5>\n<ul>\n  <li><strong>A — Wrong (IS a benefit):</strong> Keeping existing staff avoids expensive recruitment and training costs — a direct cost saving.</li>\n  <li><strong>B — Wrong (IS a benefit):</strong> If workers stay, there is less need to recruit replacements — saving management time on selection.</li>\n  <li><strong>C — Correct (NOT a benefit):</strong> The selling price of products is a marketing/pricing decision — it is completely unrelated to employee retention.</li>\n  <li><strong>D — Wrong (IS a benefit):</strong> Retained workers already know the job and don''t need retraining — reducing training costs.</li>\n</ul></div>", "modelAnswer": "C — Lower selling price."}'::jsonb),
('3-5-motivation-and-retention:mcq:e2fd1b0f', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "A worker is paid £8 per hour for working a 35-hour week. On top of this, the worker is paid a bonus of 10% of their wage for the week. How much did the worker earn in total?", "options": ["£280", "£282.80", "£308", "£420"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — £308. Step 1: £8 × 35 = £280 basic wage. Step 2: 10% bonus = £28. Step 3: £280 + £28 = £308. Do not confuse the bonus with overtime — a 10% bonus is added on top of the full week''s pay."}'::jsonb),
('3-5-motivation-and-retention:mcq:dfa35a85', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "Which of the following is a financial method of motivating workers?", "options": ["Award scheme", "Praise", "A good working environment", "Profit sharing"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D — Profit sharing. Award schemes, praise, and a good working environment are all non-financial methods. Profit sharing directly involves paying workers a share of the business''s money, making it a financial method."}'::jsonb),
('3-5-motivation-and-retention:mcq:7df1b821', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "Which of the following is a disadvantage of a method of motivating workers?", "options": ["An increase in some of the costs of the business", "Increased retention of workers", "Increased productivity of staff", "A reduction in absenteeism"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A — an increase in costs. Options B, C and D are all benefits of motivation. Increased costs (e.g. bonus payments, pay rises, fringe benefits) is the key disadvantage to the business of using financial motivation methods."}'::jsonb),
('3-5-motivation-and-retention:mcq:83875fa6', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "Jowill, an employer, raises the pay of her eight employees by £1.50 per hour. They work 35 hours each week. After the increase, Jowill''s revenue increased by £680 per week. Which statement is true?", "options": ["Jowill''s costs rose by £680 per week.", "Jowill''s profit rose by £260 per year.", "The increase in Jowill''s revenue per week exceeded her increase in costs by £260.", "Jowill''s revenue rose by £420 per week."]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Cost increase = 8 workers × £1.50 × 35 hours = £420 per week. Revenue increase = £680. £680 − £420 = £260 extra profit per week. Option A is wrong (costs rose by £420, not £680). Option B confuses weekly gain with annual. Option D is wrong (revenue rose by £680, not £420)."}'::jsonb),
('3-5-motivation-and-retention:mcq:9ec15024', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "What is a financial method of motivation that a restaurant manager may use?", "options": ["An award scheme for the chefs to develop low cost meals", "Introduce profit sharing for the chefs", "Make staff pay for any glasses or plates they break", "Praise staff who suggest how the restaurant could save money"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — profit sharing. This involves giving workers a share of the business''s profits, which is a direct financial payment. A is an award scheme (non-financial). C is a penalty, not motivation. D is praise (non-financial)."}'::jsonb),
('3-5-motivation-and-retention:mcq:ab6871f7', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "What is a non-financial method of motivation that a manufacturer of handmade wooden toys could use?", "options": ["Giving production operatives a bonus for every 1000 toys made", "Increasing the rate of pay for workers in the dusty woodcutting shed", "Praising the workers who take the greatest care when painting the designs", "Providing free private medical insurance to all workers"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — praise. This involves recognising good work verbally or formally, with no money exchanged. Options A and B involve payments (financial). Option D is a fringe benefit (financial method)."}'::jsonb),
('3-5-motivation-and-retention:mcq:b51205e7', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "Employee retention...", "options": ["extends the working hours of employees", "leads to higher recruitment costs", "minimises time spent selecting new workers", "reduces discrimination in the workplace"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. When workers stay with a business (high retention), there is less need to recruit replacements, so less time is spent on selection processes. Option B is the opposite — high retention REDUCES recruitment costs. Options A and D are not linked to the definition of retention."}'::jsonb),
('3-5-motivation-and-retention:mcq:c2f6a34b', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "A business has introduced a bonus scheme based on production targets. Which of the following statements would NOT be true?", "options": ["The bonus scheme is a form of performance-related pay", "The bonus scheme will increase business costs", "Unrealistic targets may lead to lower levels of motivation", "Workers who do not reach the target will have their basic pay reduced"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. A bonus scheme adds extra pay for reaching targets — it does NOT reduce basic pay for those who miss targets. A is true (bonuses are performance-related pay). B is true (bonuses add to costs). C is true (unrealistic targets can demotivate)."}'::jsonb),
('3-5-motivation-and-retention:mcq:0a5d0559', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "Xaio and Zhou own a building firm with 50 workers and are concerned about high recruitment costs. Which of the following would help deal with this problem?", "options": ["Decrease the hourly rate paid to workers", "Find ways to increase employee retention", "Give workers fewer fringe benefits", "Obtain additional finance from the bank"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. High recruitment costs arise from frequent staff departures. Improving retention (keeping workers longer) directly reduces the need to recruit replacements. Options A and C would likely increase turnover. Option D addresses cash but not the root problem."}'::jsonb),
('3-5-motivation-and-retention:mcq:177ea7c3', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "Which one of the following is NOT a benefit to a business of improving employee retention?", "options": ["Cost saving", "Less time spent on recruitment", "Lower selling price", "Reduced need for training"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — lower selling price. This is unrelated to employee retention. Retention reduces recruitment and training costs (A and D), and saves management time spent selecting new workers (B). A lower selling price is a pricing decision, not a retention benefit."}'::jsonb),
('3-5-motivation-and-retention:mcq:051c1734', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "A jet ski retailer with limited funds has a problem with the motivation levels of its 25 sales assistants. Which method should they use?", "options": ["Increase the sales assistants'' pay rate by £3 per hour", "Offer sales assistants a bonus of £500 for each jet ski sold", "Reduce the number of fringe benefits given to employees", "Set up a ''seller of the month'' award scheme"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D — ''seller of the month'' award scheme. The key constraint is limited funds. An award scheme is a non-financial method that costs very little but can significantly boost motivation through recognition. Options A and B are expensive financial methods. Option C would reduce motivation further."}'::jsonb),
('3-5-motivation-and-retention:mcq:7e694878', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'mcq', 'mcq', 1, '{"question": "A supermarket chain is receiving increasing complaints about the poor attitude of its sales assistants when stores are busy. What would help deal with this problem?", "options": ["Employ fewer sales assistants at each store", "Find ways to increase employee motivation at each store", "Limit the number of customers that can enter each store", "Reduce the holiday entitlement of rude employees"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Poor attitude from staff is a symptom of low motivation. Improving motivation will encourage staff to provide better customer service even when busy. Option A would make the problem worse. Option C damages revenue. Option D is a punitive measure unlikely to improve attitudes long-term."}'::jsonb),
('3-5-motivation-and-retention:tf:4c1eb09a', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tf', 'tf', 1, '{"question": "If a worker improves productivity, they will produce more than they used to in the same amount of time."}'::jsonb, '{"answer": true, "explain": "TRUE. Productivity is measured as output per worker. An improvement means more is produced in the same time period."}'::jsonb),
('3-5-motivation-and-retention:tf:96d681cd', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tf', 'tf', 1, '{"question": "If workers in a car factory improve their productivity, the cost of producing each car will fall."}'::jsonb, '{"answer": true, "explain": "TRUE. If more cars are produced using the same resources (time, workers, machinery), the fixed costs are spread across more units, lowering the average cost per car."}'::jsonb),
('3-5-motivation-and-retention:tf:3587a357', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tf', 'tf', 1, '{"question": "Motivated workers will always want to leave the business to work elsewhere."}'::jsonb, '{"answer": false, "explain": "FALSE. Motivated workers are more likely to STAY with their employer because they feel valued and rewarded. High motivation is linked to high retention, not high turnover."}'::jsonb),
('3-5-motivation-and-retention:tf:71da7be5', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tf', 'tf', 1, '{"question": "Training costs will usually fall if staff turnover is high."}'::jsonb, '{"answer": false, "explain": "FALSE. High staff turnover means new workers constantly need to be recruited and trained — this INCREASES training costs significantly. Low turnover reduces the need for repeated training."}'::jsonb),
('3-5-motivation-and-retention:tf:58999c87', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tf', 'tf', 1, '{"question": "Increased motivation reduces costs because workers are less likely to be absent."}'::jsonb, '{"answer": true, "explain": "TRUE. Motivated workers want to be at work to earn their rewards or because they enjoy their job. Lower absenteeism means fewer sick pay costs and less disruption to production."}'::jsonb),
('3-5-motivation-and-retention:tf:9343bed1', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tf', 'tf', 1, '{"question": "Motivated workers need a lot of supervision to make sure they work hard."}'::jsonb, '{"answer": false, "explain": "FALSE. Motivated workers are focused and self-directed. One key benefit of good motivation is that it REDUCES the need for supervision, saving the business money on management costs."}'::jsonb),
('3-5-motivation-and-retention:tf:c28a99c7', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tf', 'tf', 1, '{"question": "Increased motivation saves on training costs because workers are likely to remain at the firm longer and fewer new recruits are needed."}'::jsonb, '{"answer": true, "explain": "TRUE. Higher motivation leads to better retention. Retained workers already know the job, so the business spends less on training new recruits."}'::jsonb),
('3-5-motivation-and-retention:tf:81feb0c0', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tf', 'tf', 1, '{"question": "Motivated workers may help reduce business costs because they take pride in working accurately, so reducing waste."}'::jsonb, '{"answer": true, "explain": "TRUE. Motivated workers want to produce good quality work. Fewer errors and faulty goods means less raw material wasted — directly reducing production costs."}'::jsonb),
('3-5-motivation-and-retention:tf:e37163b1', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tf', 'tf', 1, '{"question": "Motivation systems can be expensive as managers need to be paid to run them."}'::jsonb, '{"answer": true, "explain": "TRUE. Managers must decide which workers receive rewards, how much to give, and whether the system is fair. This management time and oversight has a cost to the business."}'::jsonb),
('3-5-motivation-and-retention:tf:2b6f7102', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tf', 'tf', 1, '{"question": "Financial methods of motivation always increase total business costs."}'::jsonb, '{"answer": true, "explain": "TRUE. Financial methods — pay rises, bonuses, profit sharing, fringe benefits — all represent additional money the business must pay out, increasing total costs."}'::jsonb),
('3-5-motivation-and-retention:tf:e8e50179', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tf', 'tf', 1, '{"question": "Motivating workers always reduces the average costs of producing goods and services."}'::jsonb, '{"answer": false, "explain": "FALSE. While motivation can increase productivity and reduce waste (which may lower average costs), there is no guarantee. The cost of the motivation scheme itself may outweigh the savings — especially if productivity doesn''t improve enough."}'::jsonb),
('3-5-motivation-and-retention:tf:31718191', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tf', 'tf', 1, '{"question": "A modest level of staff turnover can be beneficial to a business."}'::jsonb, '{"answer": true, "explain": "TRUE. New workers bring fresh ideas, new skills, and innovative approaches. A business where staff never leave may become stagnant. Some turnover can be healthy, as long as it is not excessive."}'::jsonb),
('3-5-motivation-and-retention:learn:2ae819c5', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>These are the essential terms you must know for Unit 3.5. Learn these definitions precisely — examiners reward accurate use of business terminology.</p>\n<ul>\n  <li><strong>Motivation:</strong> The encouragement given to workers to work well. A motivated worker will feel responsible, fulfilled and happy in their work.</li>\n  <li><strong>Retention:</strong> When workers choose to stay employed in a business rather than leaving to work elsewhere.</li>\n  <li><strong>Labour Turnover:</strong> A measure of the number or proportion of staff who leave an organisation each year and who therefore need to be replaced.</li>\n  <li><strong>Productivity:</strong> A measure of output per worker. It is one way of measuring the performance of workers.</li>\n  <li><strong>Pay:</strong> The money earned by workers as a reward for the work they do.</li>\n  <li><strong>Salary:</strong> A set amount paid for a year''s work, usually split into 12 equal monthly payments.</li>\n  <li><strong>Wage:</strong> Usually a weekly system of pay, often calculated using a time-rate system (hours worked × hourly rate).</li>\n  <li><strong>Bonus:</strong> An additional payment to workers for achieving a measurable target (a form of performance-related pay).</li>\n  <li><strong>Profit Sharing:</strong> When workers receive a proportion of the profits made by a business.</li>\n  <li><strong>Fringe Benefits:</strong> Additional benefits that workers receive on top of their pay — e.g. pensions, childcare vouchers, company cars, private medical insurance, subsidised canteen meals.</li>\n  <li><strong>Praise:</strong> A non-financial method of motivating a worker by complimenting their work, making their effort feel recognised and valued.</li>\n  <li><strong>Award Scheme:</strong> A presentation of some kind (certificate, badge, voucher) to recognise somebody''s effort.</li>\n  <li><strong>Working Environment:</strong> The quality of the physical workplace and its social climate — includes how workers are treated and whether they feel valued.</li>\n</ul>", "question": "What is the difference between a bonus and profit sharing?", "options": ["A bonus pays for hitting a target; profit sharing gives a share of profits made", "They are exactly the same thing", "A bonus is only for managers; profit sharing is only for shop floor workers", "Profit sharing is paid weekly, a bonus is paid annually"]}'::jsonb, '{"answer": 0, "explain": "A bonus rewards hitting a specific target (e.g. sales figures), while profit sharing distributes a portion of the company''s overall profit among workers — the bigger the profit, the bigger the share."}'::jsonb),
('3-5-motivation-and-retention:learn:4e003fce', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'learn', 'mcq', 1, '{"readingTitle": "Why Motivation Matters: Benefits to Business", "reading": "<p>Motivation is all about <strong>improving the performance of workers</strong>. Well-motivated workers bring several key benefits to a business:</p>\n<ul>\n  <li><strong>High employee performance:</strong> Workers are efficient because they gain rewards for good quality work.</li>\n  <li><strong>High retention and low turnover:</strong> Workers are happy to remain with the employer because they feel valued and rewarded.</li>\n  <li><strong>Ease of recruitment:</strong> The firm builds a good reputation for treating staff well, attracting more applicants and higher-quality candidates.</li>\n  <li><strong>Less need for supervision:</strong> Motivated staff are focused and self-directed, saving money on supervisory roles.</li>\n  <li><strong>Low absenteeism:</strong> Workers want to be at work to earn their rewards or because they enjoy their job. Absenteeism costs money through sick pay and lost output.</li>\n  <li><strong>Reduced waste:</strong> Motivated staff take pride in producing quality work, reducing the number of faulty goods or errors.</li>\n  <li><strong>Better delivery of services:</strong> Leads to fewer complaints and more satisfied customers who return to buy again.</li>\n  <li><strong>Increased custom:</strong> Higher quality goods and services attract more customers, making the business more successful.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Gravity Payments</h4>\n  <p>In 2015, Dan Price, CEO of Gravity Payments in Seattle, raised the minimum pay for all 120 workers to $70,000 per year. For one worker, Valerie, this meant a rise from $40,000 — meaning she no longer needed a second job. Five years later, in 2020, the number of customers had doubled and the company''s turnover rose from $3.8bn to $10bn.</p>\n  <p><strong>Takeaway:</strong> Higher pay directly motivated workers, reduced turnover, and drove significant business growth — the cost of higher wages was outweighed by the huge increase in revenue and customers.</p>\n</div>", "question": "In the Gravity Payments case study, what happened after Dan Price raised the minimum pay to $70,000?", "options": ["Customer numbers doubled and turnover rose to $10bn", "The company went bankrupt within a year", "Customer numbers fell because prices had to rise", "Nothing changed for the business"]}'::jsonb, '{"answer": 0, "explain": "Despite the higher wage cost, Gravity Payments saw customer numbers double and turnover rise dramatically over five years — showing the pay rise more than paid for itself through improved motivation and performance."}'::jsonb),
('3-5-motivation-and-retention:learn:60ae092f', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'learn', 'mcq', 1, '{"readingTitle": "Why Retention Matters", "reading": "<p><strong>Retention</strong> refers to workers staying with a firm for a long period of time. High labour turnover (workers leaving frequently) creates serious problems:</p>\n<ul>\n  <li><strong>High recruitment and selection costs:</strong> Advertising, interviewing and onboarding new staff is expensive.</li>\n  <li><strong>Loss of experience and knowledge:</strong> Retained workers understand the business, its products and customers — replacing them takes time and leads to lower efficiency.</li>\n  <li><strong>High training costs:</strong> Research suggests it can cost 50–60% of a worker''s annual salary to replace them. For a worker earning £40,000, that could mean £20,000–£24,000 saved through good retention.</li>\n  <li><strong>Good morale:</strong> A stable team creates a positive atmosphere where people enjoy working together and performance improves.</li>\n  <li><strong>Attractive to recruits:</strong> Low turnover signals to potential employees that the business is a good place to work, making future recruitment easier and cheaper.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: United Utilities</h4>\n  <p>United Utilities supplies water and sewage services to around 5,000 employees across North West England — engineers, construction workers, clerical staff, financial managers and surveyors. Some work in offices in Warrington; others work on sites digging up roads to repair pipes under tight deadlines. Late work can trigger penalty payments to local councils.</p>\n  <p>United Utilities focuses on attracting and retaining staff through recognition, training and apprenticeships. In 2021, it employed 40 apprentices. It also uses a bonus scheme to reward maintenance teams for meeting deadlines.</p>\n  <p><strong>Takeaway:</strong> Retaining experienced engineers who know the pipework network and can meet tight deadlines is critical — losing them would mean high retraining costs, missed deadlines, and costly council penalties.</p>\n</div>", "question": "Roughly how much can it cost a business to replace a worker, according to research mentioned in this topic?", "options": ["1–2% of their annual salary", "50–60% of their annual salary", "Exactly £1,000 regardless of salary", "It costs nothing to replace a worker"]}'::jsonb, '{"answer": 1, "explain": "Research suggests replacing a worker can cost 50–60% of their annual salary — for someone earning £40,000, that''s potentially £20,000–£24,000, which is why good retention saves businesses significant money."}'::jsonb),
('3-5-motivation-and-retention:learn:ed992258', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'learn', 'mcq', 1, '{"readingTitle": "Financial Methods of Motivation", "reading": "<p>Financial methods of motivation involve <strong>paying money or giving monetary benefits</strong> to employees. There are four main types:</p>\n<ul>\n  <li><strong>Pay (Salary & Wage):</strong> The basic reward for work. Pay motivates because it enables workers to afford a good standard of living. Competitive pay attracts and retains staff. A <em>salary</em> is a fixed annual amount paid monthly. A <em>wage</em> is usually weekly, calculated by hours worked × hourly rate.</li>\n  <li><strong>Bonus:</strong> An additional payment triggered by reaching a measurable target — e.g. sales targets, output levels, or quality scores. It is a form of performance-related pay.</li>\n  <li><strong>Profit Sharing:</strong> A proportion of the business''s profits is shared out among workers. The bigger the profit, the larger the share — encouraging workers to be efficient and productive.</li>\n  <li><strong>Fringe Benefits:</strong> Non-cash extras on top of pay: pensions, car allowances, childcare vouchers, private medical insurance, share-buying schemes, subsidised canteen meals.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Aldi — UK''s Highest Paying Supermarket</h4>\n  <p>Aldi consistently pays higher minimum rates than any other UK supermarket. In 2021 it raised pay from £9.40 to £9.55 outside London (£11.07 in London) — exceeding the voluntary Living Wage. Aldi also pays workers during breaks, unlike some rivals.</p>\n  <p>CEO Giles Hurley linked high pay to having \"the most efficient and productive workforce.\" Aldi also invests in training and career development to recruit and retain the best people.</p>\n  <p><strong>Takeaway:</strong> High wages attract quality staff, reduce turnover and improve productivity — the cost of high pay can be offset by the efficiency and loyalty it creates.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: McDonald''s Bonuses</h4>\n  <p>Every month, McDonald''s awards bonuses to employees who work in the top 10% of its 400 UK restaurants. Rankings are based on mystery shopper reports. Store managers also receive bonuses linked to mystery shopper scores, sales growth, and profitability.</p>\n  <p><strong>Takeaway:</strong> Tying bonuses to measurable performance (mystery shopper scores) directly encourages staff to maintain high service quality, benefiting both customers and the business.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Delta Airlines — Profit Sharing</h4>\n  <p>In 2021, Delta Airlines paid over $1 billion (16.7% of profits) to its 90,000 employees worldwide. CEO Ed Bastian stated that workers deserve full credit for the company''s success.</p>\n  <p><strong>Takeaway:</strong> Sharing profits makes workers feel like genuine stakeholders in the business''s success — encouraging greater efficiency and team spirit to maximise the profit pot.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Travis Perkins — Fringe Benefits</h4>\n  <p>Travis Perkins (a timber and building merchant) offers: generous pension contributions, private medical insurance, discounted gym membership, share ''buy-as-you-earn'' schemes, a company car scheme, a subsidised bike-buying scheme, childcare vouchers, and an enhanced maternity scheme.</p>\n  <p><strong>Takeaway:</strong> A wide package of fringe benefits helps attract and retain employees by offering perks they may not be able to afford personally, boosting loyalty and reducing turnover.</p>\n</div>", "question": "What is the key difference between a salary and a wage?", "options": ["A salary is fixed monthly; a wage is hourly", "A salary is always lower than a wage", "Wages are only paid to managers", "There is no real difference between them"]}'::jsonb, '{"answer": 0, "explain": "A salary is a set amount for the year, split into equal monthly payments, while a wage is typically a weekly payment calculated using a time-rate system (hours worked × hourly rate)."}'::jsonb),
('3-5-motivation-and-retention:learn:f865bedf', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'learn', 'mcq', 1, '{"readingTitle": "Financial Methods — Advantages & Disadvantages", "reading": "<p>Using financial methods to motivate workers costs the business money. However, lower average production costs and increased revenues may offset these costs. The right method depends on the type of worker.</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>Direct motivator:</strong> Pay enables workers to afford a better standard of living, providing a clear, tangible reward for effort.</div>\n    <div class=\"pro-item\"><strong>Performance-linked bonuses:</strong> Only paid when targets are met, so the cost to the business is tied directly to improved output or sales.</div>\n    <div class=\"pro-item\"><strong>Profit sharing builds team spirit:</strong> Workers are encouraged to collaborate and be efficient, knowing higher profits mean a bigger share for everyone.</div>\n    <div class=\"pro-item\"><strong>Fringe benefits attract talent:</strong> Valued by employees who may not be able to afford private healthcare or pensions themselves, boosting loyalty and retention.</div>\n    <div class=\"pro-item\"><strong>Competitive advantage in recruitment:</strong> Businesses with strong pay packages attract higher-quality applicants from a wider pool.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>Pay is a cost:</strong> Higher wages and salaries directly increase business costs and can reduce profit margins if productivity doesn''t rise to compensate.</div>\n    <div class=\"con-item\"><strong>Time-rate pay doesn''t reward quality:</strong> A worker paid by the hour receives the same whether they work slowly or efficiently.</div>\n    <div class=\"con-item\"><strong>Unrealistic bonus targets demotivate:</strong> If workers believe targets are unachievable, bonuses have the opposite effect — they give up rather than try harder.</div>\n    <div class=\"con-item\"><strong>Profit sharing may upset shareholders:</strong> Money shared with workers reduces dividends — though if the scheme boosts profits enough, overall returns may still rise.</div>\n    <div class=\"con-item\"><strong>Fringe benefits may not suit everyone:</strong> A company car is useless to a worker who doesn''t drive; childcare vouchers mean nothing to an employee without children.</div>\n  </div>\n</div>", "question": "Why might unrealistic bonus targets actually demotivate workers rather than motivate them?", "options": ["Bonuses always demotivate workers regardless of targets", "If workers see the target as unachievable, they give up", "Bonuses are illegal if targets are too high", "Workers always prefer a fixed salary over any bonus"]}'::jsonb, '{"answer": 1, "explain": "If a bonus target feels impossible to reach, workers lose the incentive to try — the bonus scheme backfires and produces the opposite of its intended motivational effect."}'::jsonb),
('3-5-motivation-and-retention:learn:809444e0', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'learn', 'mcq', 1, '{"readingTitle": "Non-Financial Methods of Motivation", "reading": "<p>Non-financial methods motivate workers <strong>without money or benefits</strong>. They focus on recognition, respect, and the quality of the working experience. There are three main types:</p>\n<ul>\n  <li><strong>Praise:</strong> Verbal or written recognition of good work. Can be informal (a quiet word of thanks) or formal (public recognition at a ceremony). It makes workers feel their effort is noticed and valued — raising self-esteem and setting an example to others.</li>\n  <li><strong>Award Schemes:</strong> A tangible form of recognition — ''worker of the month'', certificates, vouchers, lapel badges (Asda), stars (McDonald''s), Red Letter Days, or free holidays. Even simple awards can powerfully boost morale and productivity.</li>\n  <li><strong>Working Environment:</strong> The physical conditions and social atmosphere of the workplace. Workers are more motivated when they feel safe, comfortable, respected and consulted. This includes team-bonding activities, management style, trust, and flexibility. Culture and climate matter deeply.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Google — A Positive Workplace Environment</h4>\n  <p>At Google''s California headquarters, workers are provided with free meals cooked by in-house chefs, free laundry, and childcare services. Employees are also involved in recruiting new colleagues. Research by Warwick University found that employee support at Google resulted in a 12% increase in productivity.</p>\n  <p><strong>Takeaway:</strong> Creating a genuinely supportive and enjoyable working environment — even without increasing salaries — can produce measurable productivity gains and signal that the employer values its staff.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Alphabet — Working Environment & Staff Voice</h4>\n  <p>Alphabet (a fleet maintenance company) motivates workers through a company choir that bonds teams across departments, and the APE (Alphabet Proactive Experts) initiative — a blackboard where workers write suggestions on how to improve the company. Managers always respond to these suggestions, even when not adopted.</p>\n  <p><strong>Takeaway:</strong> Giving workers a voice and actively listening to their ideas makes them feel respected and responsible — two powerful non-financial motivators that cost the business very little.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Praise in Football</h4>\n  <p>Football managers frequently shake hands, hug, or pat players on the back after substitutions or at the end of matches. This demonstrates that praise is important even for highly paid professionals — it makes workers feel valued and appreciated.</p>\n  <p><strong>Takeaway:</strong> A simple, genuine word of recognition from a manager can have a significant motivational effect regardless of how much the worker already earns.</p>\n</div>", "question": "According to the Google case study, what was the measured effect of a supportive working environment?", "options": ["A 12% increase in productivity", "A 50% reduction in staff", "No measurable change at all", "A decrease in customer satisfaction"]}'::jsonb, '{"answer": 0, "explain": "Research by Warwick University found that the supportive environment at Google — free meals, laundry, childcare — resulted in a 12% increase in productivity, even without raising salaries."}'::jsonb),
('3-5-motivation-and-retention:learn:8f046d9f', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'learn', 'mcq', 1, '{"readingTitle": "Non-Financial Methods — Advantages & Disadvantages", "reading": "<p>Non-financial methods can be very effective and sometimes cost nothing at all. However, they are not without limitations.</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>Low or zero cost:</strong> Praise costs nothing. A genuine compliment or word of thanks takes seconds but can have a lasting positive effect on morale.</div>\n    <div class=\"pro-item\"><strong>Builds long-term loyalty:</strong> Workers who feel respected and valued are more likely to stay — non-financial methods often drive longer-term retention than one-off financial rewards.</div>\n    <div class=\"pro-item\"><strong>Award schemes boost public recognition:</strong> Recognising good work in front of peers raises self-esteem and sets a standard for others to aspire to.</div>\n    <div class=\"pro-item\"><strong>Positive environment improves teamwork:</strong> Activities like team-bonding days or a company choir build strong workplace relationships, improving collaboration and communication.</div>\n    <div class=\"pro-item\"><strong>Inclusive:</strong> A good working environment benefits all employees equally, unlike financial rewards which may only go to top performers.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>Some workers may find praise insufficient:</strong> Workers expecting financial recognition may view praise as a substitute for a pay rise — creating cynicism rather than motivation.</div>\n    <div class=\"con-item\"><strong>Award schemes can cause conflict:</strong> If only one worker wins ''employee of the month'', others may feel overlooked or demotivated, especially if the process appears unfair.</div>\n    <div class=\"con-item\"><strong>Environment improvements cost money:</strong> Redecorating offices, buying new furniture, or funding team days out all have a direct cost to the business.</div>\n    <div class=\"con-item\"><strong>Lost production during activities:</strong> If workers attend bonding activities or ceremonies during working hours, output may temporarily fall.</div>\n    <div class=\"con-item\"><strong>Not universally effective:</strong> Different workers are motivated differently. What energises one person may mean little to another.</div>\n  </div>\n</div>", "question": "Why can award schemes like ''Employee of the Month'' sometimes cause problems?", "options": ["They are too expensive for most businesses to afford", "Workers who lose out may feel overlooked or unfair", "They are illegal in most countries", "They only work for part-time staff"]}'::jsonb, '{"answer": 1, "explain": "While award schemes can boost the winner''s motivation, workers who consistently miss out may become demotivated or feel the process is unfair — a real disadvantage of this non-financial method."}'::jsonb),
('3-5-motivation-and-retention:learn:c6cc3e85', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'learn', 'mcq', 1, '{"readingTitle": "Pay Calculations", "reading": "<p>You must be able to calculate pay, bonuses, and profit shares in the exam. Here are the key formulas and worked examples:</p>\n\n<div class=\"formula-box\">\n  <strong>Time-Rate Weekly Wage =</strong> Hours Worked &times; Hourly Rate\n</div>\n\n<div class=\"formula-box\">\n  <strong>Overtime Pay =</strong> Overtime Hours &times; (Hourly Rate &times; Overtime Multiplier)\n</div>\n\n<div class=\"formula-box\">\n  <strong>Profit Share per Worker =</strong> (Total Profit &times; % to share) &divide; Number of Workers\n</div>\n\n<div class=\"formula-box\">\n  <strong>Bonus per Worker =</strong> Total Bonus Pool &divide; Number of Workers in Team\n</div>\n\n<p><strong>Worked Example 1 — Wage + Overtime (Angus Deade):</strong><br>\n£9/hour × 35 hours × 4 weeks = £1,260<br>\nOvertime: 12 hours × £13.50 (time and a half) = £162<br>\n<strong>Total = £1,422</strong></p>\n\n<p><strong>Worked Example 2 — Salary + Bonus (Fabrice N''gono):</strong><br>\nBasic salary: £800/month<br>\nBonus pool: £960 ÷ 8 workers = £120 bonus<br>\n<strong>Total = £920</strong></p>\n\n<p><strong>Worked Example 3 — Salary + Profit Share + Fringe Benefits (Alastair Munro):</strong><br>\nSalary: £80,000<br>\nProfit share: 2% × £2,000,000 = £40,000<br>\n<strong>Total = £120,000 + fringe benefits (company car + health insurance)</strong></p>\n\n<p><strong>Worked Example 4 — Salary + Bonus (Wasim Ikram):</strong><br>\nSalary: £30,000<br>\nBonus: 15% × £30,000 = £4,500<br>\n<strong>Total = £34,500</strong></p>", "question": "A worker earns £8 per hour and works 30 hours in a week, plus 5 hours of overtime at time-and-a-half. What is their total pay for the week?", "options": ["£240", "£300", "£280", "£320"]}'::jsonb, '{"answer": 1, "explain": "Basic pay: 30 × £8 = £240. Overtime: 5 × (£8 × 1.5) = 5 × £12 = £60. Total = £240 + £60 = £300."}'::jsonb),
('3-5-motivation-and-retention:learn:d21f5ca4', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'learn', 'mcq', 1, '{"readingTitle": "Evaluating Motivation: Are the Costs Worth It?", "reading": "<p>Whether a motivation system is worthwhile depends on how effectively it improves performance <strong>compared to its cost</strong>. This is a key evaluation point in the exam.</p>\n<ul>\n  <li><strong>Financial methods cost money</strong> — bonuses, pay rises, profit shares and fringe benefits all reduce profits available to owners/shareholders.</li>\n  <li><strong>Management costs:</strong> Managers must decide who gets rewards, how much, and arrange delivery fairly. If the system is seen as unfair, it can <em>de-motivate</em> workers who miss out.</li>\n  <li><strong>Non-financial methods</strong> may also cost money (awards, activities) or lost output (if workers are away from their desks).</li>\n</ul>\n<p>However, the benefits may outweigh the costs if motivation leads to:</p>\n<ul>\n  <li>Higher productivity &rarr; lower cost per unit &rarr; higher profit margins</li>\n  <li>Lower absenteeism &rarr; fewer sick pay costs &rarr; consistent output</li>\n  <li>Higher retention &rarr; lower recruitment and training costs</li>\n  <li>Better quality &rarr; fewer complaints &rarr; more repeat customers &rarr; higher revenue</li>\n</ul>\n<p><strong>Key evaluation phrase:</strong> <em>\"It depends on whether the increase in productivity and reduction in costs outweighs the cost of the motivational method used.\"</em></p>\n<p><strong>Also consider:</strong> A modest level of staff turnover can actually be beneficial — new workers bring fresh ideas, perspectives and energy. Good retention is important, but a business that <em>never</em> loses any staff may miss out on innovation.</p>", "question": "Why might a small amount of staff turnover actually be good for a business, according to this topic?", "options": ["It saves money on holiday pay", "New workers bring fresh ideas, perspectives and energy", "It means the business doesn''t need a HR department", "Turnover always improves productivity regardless of cause"]}'::jsonb, '{"answer": 1, "explain": "While high retention is generally beneficial, a business that never loses any staff may stagnate. A modest level of turnover brings in new ideas and skills, which is why ''optimal retention'' rather than ''zero turnover'' is the goal."}'::jsonb),
('3-5-motivation-and-retention:misc:cbb503e3', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Only financial methods can motivate workers.</p><p><strong>✅ The correct idea:</strong> Non-financial methods — praise, award schemes, and a positive working environment — can be equally or more effective. Research consistently shows that recognition from a manager can be the highest-ranked motivator. Non-financial methods also tend to produce longer-term benefits and cost the business far less.</p>", "question": "Can non-financial methods like praise be as effective as financial rewards for motivating workers?", "options": ["No — only money motivates workers", "Yes — praise can be a top motivator", "Only for senior managers", "Only in small businesses"]}'::jsonb, '{"answer": 1, "explain": "Non-financial methods such as praise and recognition are consistently shown to be highly effective motivators, often producing longer-term benefits than one-off financial rewards, and at a much lower cost to the business."}'::jsonb),
('3-5-motivation-and-retention:misc:3ccea2f9', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> All workers are motivated by the same things.</p><p><strong>✅ The correct idea:</strong> Different workers respond to different motivators based on their personality, life stage, and role. A one-size-fits-all approach is ineffective. Businesses should use a range of financial and non-financial methods to suit all employees.</p>", "question": "Why is a ''one-size-fits-all'' approach to motivation often ineffective?", "options": ["It is too expensive to implement", "Workers respond to different things", "It is illegal under employment law", "It only works for full-time staff"]}'::jsonb, '{"answer": 1, "explain": "Workers are individuals with different needs and priorities — a company car might motivate one worker but mean nothing to another who doesn''t drive. Businesses need a range of methods to motivate everyone effectively."}'::jsonb),
('3-5-motivation-and-retention:misc:8327ac77', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> High retention is always better for a business.</p><p><strong>✅ The correct idea:</strong> While high retention reduces costs and maintains experience, a modest level of turnover can be advantageous — new staff bring fresh ideas, skills and perspectives. The goal is optimal retention, not zero turnover.</p>", "question": "Is the goal of a business to achieve zero staff turnover?", "options": ["Yes, zero turnover is always the ideal outcome", "No — optimal retention is the goal, not zero turnover", "Yes, but only for management positions", "No, businesses should aim for maximum turnover instead"]}'::jsonb, '{"answer": 1, "explain": "While high retention has clear benefits, a small amount of turnover is healthy — new staff bring fresh perspectives and skills that an unchanging workforce might lack."}'::jsonb),
('3-5-motivation-and-retention:misc:451582bd', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A bonus scheme will always motivate workers to work harder.</p><p><strong>✅ The correct idea:</strong> Bonuses only motivate if the targets are realistic. If targets are seen as unachievable, workers will give up rather than try harder — the bonus actually demotivates. Targets must be challenging but attainable.</p>", "question": "What happens if bonus targets are seen by workers as unachievable?", "options": ["Workers always try even harder to reach them", "Workers give up trying, so the bonus demotivates", "The business must pay the bonus anyway", "Nothing changes in worker behaviour"]}'::jsonb, '{"answer": 1, "explain": "If targets feel impossible, workers lose the incentive to push for them — meaning an unrealistic bonus scheme can actually demotivate staff rather than encourage harder work."}'::jsonb),
('3-5-motivation-and-retention:misc:c086699c', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Motivation only affects how happy workers feel — it doesn''t impact business profits.</p><p><strong>✅ The correct idea:</strong> Motivation has direct financial consequences: lower absenteeism reduces costs, higher productivity increases output, better quality reduces waste, and improved service grows customer loyalty — all of which improve profitability.</p>", "question": "How does worker motivation actually affect business profits?", "options": ["It doesn''t — motivation only affects employee happiness", "Through less absenteeism and higher output overall", "Only through reduced wage costs", "Motivation has no measurable business impact"]}'::jsonb, '{"answer": 1, "explain": "Motivation has real financial consequences — it reduces costs (absenteeism, waste) and increases revenue (productivity, customer loyalty), directly affecting the bottom line, not just how workers feel."}'::jsonb),
('3-5-motivation-and-retention:misc:d3ef7202', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Profit sharing reduces profits because money is given to workers.</p><p><strong>✅ The correct idea:</strong> Profit sharing can actually increase overall profits if it motivates workers to be more efficient and productive. Shareholders may benefit from a larger profit pot even after the workers'' share has been distributed.</p>", "question": "Can profit sharing actually increase a business''s overall profits?", "options": ["No — sharing profits always reduces total profit", "Yes — efficiency gains can grow the total profit", "Only if the business has fewer than 10 employees", "Profit sharing has no effect on motivation at all"]}'::jsonb, '{"answer": 1, "explain": "If profit sharing motivates workers to be more productive and efficient, the total profit generated can grow — meaning shareholders may end up with a larger amount even after the workers'' share is paid out, as seen in the Delta Airlines example."}'::jsonb),
('3-5-motivation-and-retention:misc:f3ef7aff', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Employee retention is important just because it makes workers feel good.</p><p><strong>✅ The correct idea:</strong> Examiners want business-focused reasons. Retention reduces recruitment and training costs (which can be 50–60% of annual salary), maintains expertise and customer relationships, supports morale, and makes the business more attractive to future recruits.</p>", "question": "When explaining why retention matters in an exam answer, what should you focus on?", "options": ["How happy it makes the workers feel", "Business reasons, like lower recruitment costs", "Only the legal requirements around retention", "The personal opinions of the business owner"]}'::jsonb, '{"answer": 1, "explain": "Examiners want business-level reasoning — cost savings on recruitment and training, retained expertise, and improved ability to attract future staff — not just statements about employee happiness."}'::jsonb),
('3-5-motivation-and-retention:misc:f64c039d', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Fringe benefits motivate all workers equally.</p><p><strong>✅ The correct idea:</strong> Fringe benefits are not universally valued. A company car is useless to someone who doesn''t drive; childcare vouchers don''t benefit workers without children. The right fringe benefit depends on the individual worker''s needs and life circumstances.</p>", "question": "Why might a company car fail to motivate a particular worker?", "options": ["Company cars are always too expensive for businesses to offer", "If the worker doesn''t drive, the benefit is irrelevant to them", "Company cars are illegal as a fringe benefit", "All workers value a company car equally"]}'::jsonb, '{"answer": 1, "explain": "Fringe benefits only motivate when they match a worker''s actual needs and circumstances — a company car means nothing to someone who doesn''t drive, just as childcare vouchers mean nothing to a worker without children."}'::jsonb),
('3-5-motivation-and-retention:misc:6978d05a', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Salary is better than wages for motivating workers.</p><p><strong>✅ The correct idea:</strong> Neither is automatically better. Salary provides stability and can motivate through promotion prospects. Wages with time-rate pay are simple but don''t directly reward high performance. The best system depends on the type of job and what the business wants to incentivise.</p>", "question": "Is a salary always a better motivator than a wage?", "options": ["Yes, salary is always more motivating", "No, the better choice depends on the job itself", "No, wages are always more motivating", "Salary and wages are identical in every way"]}'::jsonb, '{"answer": 1, "explain": "Neither system is universally superior. Salary offers stability, while time-rate wages are simple to calculate but don''t reward performance directly — the right choice depends on the role and business goals."}'::jsonb),
('3-5-motivation-and-retention:misc:c20f3bb1', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Praise is only effective for low-paid workers who don''t earn much money.</p><p><strong>✅ The correct idea:</strong> Praise is important at all levels — even highly paid professional footballers visibly respond to recognition from their managers. The desire to feel valued and appreciated is a universal human need, not limited by income level.</p>", "question": "According to the football case study, does praise only matter to low-paid workers?", "options": ["Yes — high earners don''t need recognition", "No — even top footballers respond to praise", "Praise only matters to part-time workers", "Praise has no effect on professional athletes"]}'::jsonb, '{"answer": 1, "explain": "The football example shows that even very highly paid professionals respond to genuine praise and recognition — the need to feel valued is universal and not limited to lower-income workers."}'::jsonb),
('3-5-motivation-and-retention:tips:fd636f92', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tips', 'mcq', 1, '{"readingTitle": "Identify / State — 1 mark — One Point. Full Stop. Move On.", "reading": "\n      <p>A 1-mark <strong>''State'' or ''Identify''</strong> question needs exactly one correct point. No explanation. No examples. No paragraphs.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li>One clear, specific point = 1 mark ✅</li>\n        <li>A vague or general point = 0 marks ❌</li>\n      </ul>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"Motivation.\"</em><br/>\n      This is just the topic name — it doesn''t say anything useful about why retention matters.</p>\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>\"Lower recruitment costs.\"</em><br/>\n      Specific, relevant, directly answers the question.</p>\n      <p><strong>⚠️ Examiner Warning:</strong> On the Redrow Homes question, many students wrote \"workers feel happier\" — this received no marks because it describes a personal benefit to the worker, not an importance to the business. Always write from the <strong>business''s perspective</strong>.</p>\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write a definition of the term when asked to identify something. If asked \"identify a financial method of motivation,\" write \"profit sharing\" — not \"financial methods are those involving money.\"</p>\n    ", "question": "Why did the answer ''workers feel happier'' score zero marks on the Redrow Homes question about why retention is important to a business?", "options": ["A worker feeling, not a business reason", "It was spelled incorrectly", "It was too long an answer", "Redrow Homes does not employ any workers"]}'::jsonb, '{"answer": 0, "explain": "The question asks for the importance to the business, so an answer focused on worker feelings doesn''t answer the question — always write from the business''s perspective for these marks."}'::jsonb),
('3-5-motivation-and-retention:tips:82928f0b', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — Understanding + Application = 2 Marks", "reading": "\n      <p>A 2-mark <strong>''Explain''</strong> question requires two linked points: a reason <strong>why</strong> something is true, applied to the business in the case study.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Point (U):</strong> Give the business reason</li>\n        <li><strong>Application (APP):</strong> Link it specifically to the business in the case study</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark):</strong><br/>\n      <em>\"Retention is important because it reduces recruitment costs.\"</em><br/>\n      This is correct but has NO application — it scores only 1 mark.</p>\n      <p><strong>✅ Good Answer (2 marks):</strong><br/>\n      <em>\"Retention reduces recruitment costs (U), which is especially important for United Utilities as it employs 5,000 workers and constantly replacing staff would be very expensive (APP).\"</em></p>\n      <p><strong>⚠️ Examiner Warning:</strong> Application marks cannot be awarded without the understanding mark. You must earn U before you can earn APP. Always make your point first, then apply it.</p>\n      <p><strong>Sentence Starters:</strong><br/>\n      \"This is particularly important for [Business] because...\"<br/>\n      \"In the case of [Business], this means that...\"</p>\n    ", "question": "What is missing from the answer: ''Retention is important because it reduces recruitment costs''?", "options": ["Nothing — it scores full marks", "A link to the named business", "A definition of recruitment", "A calculation"]}'::jsonb, '{"answer": 1, "explain": "This answer gives the understanding point (U) but stops there — without applying it specifically to the business in the case study, it can only score 1 of the 2 marks available."}'::jsonb),
('3-5-motivation-and-retention:tips:34e8d8ec', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: U → APP → AN", "reading": "\n      <p>A 3-mark <strong>''Analyse''</strong> question follows a strict three-step structure. Miss any one of these steps and you lose a mark.</p>\n      <p><strong>The Three-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State the benefit or concept clearly.</li>\n        <li><strong>Step 2 — Application (APP):</strong> Link it directly to the specific business in the case study. Quote or reference the case study.</li>\n        <li><strong>Step 3 — Analysis (AN):</strong> State the financial or operational impact on the business (costs, revenue, reputation, profit).</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer (1 mark):</strong><br/>\n      <em>\"A bonus motivates workers to work harder.\"</em><br/>\n      This is knowledge only — no application, no analysis. Maximum 1 mark.</p>\n\n      <p><strong>✅ Good Answer (3 marks):</strong><br/>\n      <em>\"A bonus scheme motivates workers to meet targets (U). For United Utilities, the bonus is paid when maintenance teams meet their road-repair deadlines (APP). This means United Utilities avoids paying penalty charges to local councils, protecting the company''s profits (AN).\"</em></p>\n\n      <p><strong>🚫 Zero Marks for Analysis without Application:</strong> If you don''t use the case study, you cannot score the analysis mark — even if your business knowledge is perfect. Examiners will award 0 for analysis if there is no application.</p>\n\n      <p><strong>The \"So What?\" Rule:</strong> After each point, ask yourself \"So what does this mean for the business?\" Keep pushing until you hit a bottom-line impact: costs, revenue, profit, reputation, or customer numbers.</p>\n    ", "question": "Can you score the analysis (AN) mark on a 3-mark question if you don''t apply your point to the case study business?", "options": ["Yes, knowledge alone is enough for all 3 marks", "No — zero marks without application to it", "Yes, but only for calculation questions", "It depends on how long the answer is"]}'::jsonb, '{"answer": 1, "explain": "Without application to the specific business in the case study, you cannot score the analysis mark — even with perfect business knowledge. The chain must be U → APP → AN in that order."}'::jsonb),
('3-5-motivation-and-retention:tips:91b90a83', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tips', 'mcq', 1, '{"readingTitle": "Recommend — 3 marks — Make a Choice, Compare Both, Use Context", "reading": "\n      <p>A 3-mark <strong>''Recommend''</strong> question (like the Walkers Ltd question) requires a clear decision with a comparative justification using the case study.</p>\n      <p><strong>The Three-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Judgement (1 mark):</strong> State your clear recommendation (e.g., \"Walkers Ltd should use award schemes\").</li>\n        <li><strong>Step 2 — Contextual justification (2 marks):</strong> Explain WHY your choice is better THAN the other option, using details from the case study.</li>\n      </ul>\n      <p><strong>⚠️ Critical Rule:</strong> Your justification MUST cover BOTH methods — explain why the chosen method is better AND why the other is less suitable. You cannot score full marks by only praising your chosen option.</p>\n\n      <p><strong>❌ Bad Answer (1 mark):</strong><br/>\n      <em>\"Walkers Ltd should use award schemes because they make workers feel valued.\"</em><br/>\n      This gives a judgement and a reason, but doesn''t compare or use the case study.</p>\n\n      <p><strong>✅ Good Answer (3 marks):</strong><br/>\n      <em>\"Walkers Ltd should use an award scheme (JUDGEMENT). The survey shows workers feel unvalued, so public recognition would directly address this issue. Unlike a wage increase — which workers may take for granted once it becomes the norm — an award scheme offers visible, ongoing recognition that continuously motivates workers (COMPARISON + CONTEXT).\"</em></p>\n    ", "question": "What is the critical rule for scoring full marks on a ''Recommend'' question?", "options": ["Only explain why your chosen method is good", "You must compare both options, not just one", "Write as many recommendations as possible", "Avoid using the case study"]}'::jsonb, '{"answer": 1, "explain": "Full marks require a genuine comparison — you must justify your chosen method while also explaining why the alternative is less suitable, both grounded in the case study context."}'::jsonb),
('3-5-motivation-and-retention:tips:35126375', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 7 marks — Both Sides + A Justified Conclusion", "reading": "\n      <p>A 7-mark question is marked using a levels-of-response grid. To reach the top level, you must demonstrate <strong>application, analysis, AND strong evaluation</strong>.</p>\n      <p><strong>Structure your answer in 3 paragraphs:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1 — AN & APP:</strong> Analyse the first impact, applied to the business in context.</li>\n        <li><strong>Paragraph 2 — AN & APP:</strong> Analyse a second impact (or the other side), applied to the business in context.</li>\n        <li><strong>Paragraph 3 — EVAL (3 parts):</strong>\n          <ul>\n            <li><strong>Decision:</strong> Make a clear judgement.</li>\n            <li><strong>Context:</strong> Reference something specific from the case study.</li>\n            <li><strong>Impact/Reasoning:</strong> Explain the consequence of your decision for the business.</li>\n          </ul>\n        </li>\n      </ul>\n      <p><strong>The \"It depends on...\" Rule:</strong> A conclusion that just repeats your earlier points scores zero evaluation marks. Your conclusion MUST add something new — a condition, a comparison, or a business-specific reason.</p>\n      <p><strong>✅ Strong Evaluation Sentence Starters:</strong><br/>\n      \"Overall, I recommend... because...\"<br/>\n      \"However, this depends entirely on whether...\"<br/>\n      \"Ultimately, [Option X] is more suitable for [Business] because, given that [context]...\"</p>\n      <p><strong>⚠️ Examiner Warning — Waitrose Question:</strong> Many students wrote about profit sharing in general without applying it to Waitrose''s 50,000 employees or its high-income customer base. The evaluation mark requires a contextual judgement — mentioning Waitrose specifically.</p>\n    ", "question": "What is required to score the evaluation marks at the end of a 7-mark question?", "options": ["Simply repeating your earlier points in different words", "A decision, case-study context, and its business impact", "Listing as many advantages as possible", "A definition of the key term"]}'::jsonb, '{"answer": 1, "explain": "A strong conclusion needs three things: a clear decision, a specific detail from the case study, and the reasoning behind why that decision matters for that particular business — simply repeating earlier points scores zero."}'::jsonb),
('3-5-motivation-and-retention:tips:8d128821', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 9 marks — All Five Skills: K → U → APP → AN → EVAL", "reading": "\n      <p>The 9-mark question tests ALL five assessment objectives. Every skill must be <strong>explicit</strong> — the examiner cannot award implied skills.</p>\n      <p><strong>Structure your answer in 4 paragraphs:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1 — K & U:</strong> Define the key concept and explain how it works. Keep this brief — one or two sentences is enough to secure both marks.</li>\n        <li><strong>Paragraph 2 — AN & APP:</strong> Analyse the first impact on motivation or retention using the business in the case study.</li>\n        <li><strong>Paragraph 3 — AN & APP:</strong> Analyse the second impact (the other side or another consequence), again applied to the business.</li>\n        <li><strong>Paragraph 4 — EVAL (3 points):</strong>\n          <ul>\n            <li><strong>Decision:</strong> Make a clear, overall judgement.</li>\n            <li><strong>Context:</strong> Use a specific detail from the case study to justify your position.</li>\n            <li><strong>Impact/Reasoning:</strong> Explain the long-term or significant consequence of your judgement for the business.</li>\n          </ul>\n        </li>\n      </ul>\n      <p><strong>✅ Sentence Starters — Paragraph 1 (K & U):</strong><br/>\n      \"Ethics refers to... (K). Ethical treatment of workers means that a business... (U).\"</p>\n      <p><strong>✅ Sentence Starters — Paragraphs 2 & 3 (AN & APP):</strong><br/>\n      \"This means M&S workers are likely to... (APP). As a result, M&S will benefit from... which will reduce/increase... (AN).\"</p>\n      <p><strong>✅ Sentence Starters — Paragraph 4 (EVAL):</strong><br/>\n      \"Overall, ethical treatment will have a [positive/negative] impact on M&S (DECISION), particularly because M&S employs over 50,000 people and targets high-income customers who expect good quality service (CONTEXT). This means the long-term impact on retention is likely to be greater than the short-term cost of implementing ethical practices (IMPACT).\"</p>\n      <p><strong>⚠️ Examiner Warning — M&S Question:</strong> Most candidates could apply ethical treatment to motivation but fewer could link it to retention AND analyse both impacts on the business. Many candidates also failed to score the knowledge mark by not defining ethics clearly at the start.</p>\n    ", "question": "How many separate assessment objectives must a 9-mark answer demonstrate?", "options": ["Just one — knowledge", "All five: K, U, APP, AN, EVAL", "Only Analysis and Evaluation", "Two — Application and Evaluation"]}'::jsonb, '{"answer": 1, "explain": "A 9-mark question tests all five assessment objectives (K, U, APP, AN, EVAL). Every skill must be explicitly shown in the answer — examiners cannot award marks for skills that are only implied."}'::jsonb),
('3-5-motivation-and-retention:tips:81bea9b7', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'tips', 'mcq', 1, '{"readingTitle": "Calculation — 3 marks — Show Every Step or Risk Losing Marks", "reading": "\n      <p>Calculation questions carry 3 marks, each for a distinct step. You can earn marks even if your final answer is wrong — <strong>always show your working</strong>.</p>\n      <p><strong>Common Calculation Types:</strong></p>\n      <ul>\n        <li>Time-rate wage: Hours × Hourly Rate</li>\n        <li>Overtime: Overtime Hours × (Rate × Multiplier, e.g. 1.5 for time-and-a-half)</li>\n        <li>Bonus calculation: Bonus Pool ÷ Number of Workers</li>\n        <li>Profit share: Total Profit × % ÷ 100 ÷ Number of Workers</li>\n        <li>Percentage increase: Original Amount × (1 + %/100)</li>\n      </ul>\n      <p><strong>Example — James at McDonald''s (£7.00/hr, 16 hrs, 10% rise):</strong><br/>\n      Step 1: 10% of £7.00 = £0.70<br/>\n      Step 2: New rate = £7.00 + £0.70 = £7.70<br/>\n      Step 3: £7.70 × 16 hours = £123.20 ✅</p>\n      <p><strong>Example — Saranne''s profit share:</strong><br/>\n      Step 1: 5% of £15,000 = £750<br/>\n      Step 2: £750 ÷ 3 workers = £250 each<br/>\n      Step 3: £12,000 + £250 = £12,250 ✅</p>\n      <p><strong>⚠️ OFR (Own Figure Rule):</strong> If you make an error in step 1 but correctly complete steps 2 and 3 using your wrong figure, you can still earn the marks for those later steps. This is why showing working is essential.</p>\n    ", "question": "If you make a mistake on step 1 of a calculation but correctly complete steps 2 and 3 using your (wrong) figure, what happens under the Own Figure Rule (OFR)?", "options": ["You score 0 marks for the whole question", "You still earn marks for steps 2 and 3 despite the error", "You must restart the calculation from scratch", "Only the final answer is marked, regardless of working shown"]}'::jsonb, '{"answer": 1, "explain": "The Own Figure Rule means examiners credit each correct step of working even if an earlier step contained an error — which is exactly why showing all your working is essential, not optional."}'::jsonb),
