('3-5-motivation-and-retention:match:27d80f8d', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Motivation”?", "options": ["When workers choose to stay employed in a business rather than leaving to work elsewhere.", "A measure of the number or proportion of staff who leave an organisation each year and who need to be replaced.", "A measure of output per worker — one way of measuring the performance of employees.", "The encouragement given to workers to work well, making them feel responsible, fulfilled and happy."]}'::jsonb, '{"answer": 3, "explain": "“Motivation” means: The encouragement given to workers to work well, making them feel responsible, fulfilled and happy."}'::jsonb),
('3-5-motivation-and-retention:match:6c74e627', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Retention”?", "options": ["A measure of the number or proportion of staff who leave an organisation each year and who need to be replaced.", "When workers choose to stay employed in a business rather than leaving to work elsewhere.", "A measure of output per worker — one way of measuring the performance of employees.", "A fixed amount paid for a year''s work, usually divided into 12 equal monthly payments."]}'::jsonb, '{"answer": 1, "explain": "“Retention” means: When workers choose to stay employed in a business rather than leaving to work elsewhere."}'::jsonb),
('3-5-motivation-and-retention:match:0903e76a', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Labour Turnover”?", "options": ["A measure of output per worker — one way of measuring the performance of employees.", "A fixed amount paid for a year''s work, usually divided into 12 equal monthly payments.", "A weekly system of pay calculated by multiplying hours worked by the hourly rate.", "A measure of the number or proportion of staff who leave an organisation each year and who need to be replaced."]}'::jsonb, '{"answer": 3, "explain": "“Labour Turnover” means: A measure of the number or proportion of staff who leave an organisation each year and who need to be replaced."}'::jsonb),
('3-5-motivation-and-retention:match:adf2d659', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Productivity”?", "options": ["A fixed amount paid for a year''s work, usually divided into 12 equal monthly payments.", "A weekly system of pay calculated by multiplying hours worked by the hourly rate.", "An additional payment to workers for achieving a measurable target, such as reaching a sales goal or production level.", "A measure of output per worker — one way of measuring the performance of employees."]}'::jsonb, '{"answer": 3, "explain": "“Productivity” means: A measure of output per worker — one way of measuring the performance of employees."}'::jsonb),
('3-5-motivation-and-retention:match:b9e5dd51', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Salary”?", "options": ["A weekly system of pay calculated by multiplying hours worked by the hourly rate.", "A fixed amount paid for a year''s work, usually divided into 12 equal monthly payments.", "An additional payment to workers for achieving a measurable target, such as reaching a sales goal or production level.", "When workers receive a set proportion of the profits made by a business."]}'::jsonb, '{"answer": 1, "explain": "“Salary” means: A fixed amount paid for a year''s work, usually divided into 12 equal monthly payments."}'::jsonb),
('3-5-motivation-and-retention:match:d6076934', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Wage”?", "options": ["An additional payment to workers for achieving a measurable target, such as reaching a sales goal or production level.", "A weekly system of pay calculated by multiplying hours worked by the hourly rate.", "When workers receive a set proportion of the profits made by a business.", "Additional non-cash benefits on top of pay, such as pensions, childcare vouchers, company cars and private medical insurance."]}'::jsonb, '{"answer": 1, "explain": "“Wage” means: A weekly system of pay calculated by multiplying hours worked by the hourly rate."}'::jsonb),
('3-5-motivation-and-retention:match:7b3a4e92', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Bonus”?", "options": ["An additional payment to workers for achieving a measurable target, such as reaching a sales goal or production level.", "When workers receive a set proportion of the profits made by a business.", "Additional non-cash benefits on top of pay, such as pensions, childcare vouchers, company cars and private medical insurance.", "A non-financial method of motivating workers by complimenting their work and making their effort feel recognised."]}'::jsonb, '{"answer": 0, "explain": "“Bonus” means: An additional payment to workers for achieving a measurable target, such as reaching a sales goal or production level."}'::jsonb),
('3-5-motivation-and-retention:match:c70bd6ce', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Profit Sharing”?", "options": ["Additional non-cash benefits on top of pay, such as pensions, childcare vouchers, company cars and private medical insurance.", "When workers receive a set proportion of the profits made by a business.", "A non-financial method of motivating workers by complimenting their work and making their effort feel recognised.", "A tangible form of recognition — such as a certificate, badge, or voucher — presented to acknowledge a worker''s effort."]}'::jsonb, '{"answer": 1, "explain": "“Profit Sharing” means: When workers receive a set proportion of the profits made by a business."}'::jsonb),
('3-5-motivation-and-retention:match:a3912d8e', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fringe Benefits”?", "options": ["Additional non-cash benefits on top of pay, such as pensions, childcare vouchers, company cars and private medical insurance.", "A non-financial method of motivating workers by complimenting their work and making their effort feel recognised.", "A tangible form of recognition — such as a certificate, badge, or voucher — presented to acknowledge a worker''s effort.", "The quality of the physical workplace and its social climate, including how workers are treated and whether they feel respected."]}'::jsonb, '{"answer": 0, "explain": "“Fringe Benefits” means: Additional non-cash benefits on top of pay, such as pensions, childcare vouchers, company cars and private medical insurance."}'::jsonb),
('3-5-motivation-and-retention:match:d9d65429', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Praise”?", "options": ["A tangible form of recognition — such as a certificate, badge, or voucher — presented to acknowledge a worker''s effort.", "A non-financial method of motivating workers by complimenting their work and making their effort feel recognised.", "The quality of the physical workplace and its social climate, including how workers are treated and whether they feel respected.", "When workers take time off work without good reason. High absenteeism is a sign of poor motivation and increases business costs."]}'::jsonb, '{"answer": 1, "explain": "“Praise” means: A non-financial method of motivating workers by complimenting their work and making their effort feel recognised."}'::jsonb),
('3-5-motivation-and-retention:match:d6c8fb03', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Award Scheme”?", "options": ["The quality of the physical workplace and its social climate, including how workers are treated and whether they feel respected.", "A tangible form of recognition — such as a certificate, badge, or voucher — presented to acknowledge a worker''s effort.", "When workers take time off work without good reason. High absenteeism is a sign of poor motivation and increases business costs.", "A system where workers receive extra pay based on how well they perform against a measurable target."]}'::jsonb, '{"answer": 1, "explain": "“Award Scheme” means: A tangible form of recognition — such as a certificate, badge, or voucher — presented to acknowledge a worker''s effort."}'::jsonb),
('3-5-motivation-and-retention:match:d9a6a663', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Working Environment”?", "options": ["When workers take time off work without good reason. High absenteeism is a sign of poor motivation and increases business costs.", "A system where workers receive extra pay based on how well they perform against a measurable target.", "The encouragement given to workers to work well, making them feel responsible, fulfilled and happy.", "The quality of the physical workplace and its social climate, including how workers are treated and whether they feel respected."]}'::jsonb, '{"answer": 3, "explain": "“Working Environment” means: The quality of the physical workplace and its social climate, including how workers are treated and whether they feel respected."}'::jsonb),
('3-5-motivation-and-retention:match:03b646e0', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Absenteeism”?", "options": ["A system where workers receive extra pay based on how well they perform against a measurable target.", "When workers take time off work without good reason. High absenteeism is a sign of poor motivation and increases business costs.", "The encouragement given to workers to work well, making them feel responsible, fulfilled and happy.", "When workers choose to stay employed in a business rather than leaving to work elsewhere."]}'::jsonb, '{"answer": 1, "explain": "“Absenteeism” means: When workers take time off work without good reason. High absenteeism is a sign of poor motivation and increases business costs."}'::jsonb),
('3-5-motivation-and-retention:match:64f6cd73', '3-5-motivation-and-retention', '3.5 Motivation and Retention', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Performance-Related Pay”?", "options": ["The encouragement given to workers to work well, making them feel responsible, fulfilled and happy.", "When workers choose to stay employed in a business rather than leaving to work elsewhere.", "A measure of the number or proportion of staff who leave an organisation each year and who need to be replaced.", "A system where workers receive extra pay based on how well they perform against a measurable target."]}'::jsonb, '{"answer": 3, "explain": "“Performance-Related Pay” means: A system where workers receive extra pay based on how well they perform against a measurable target."}'::jsonb),
('3-6-training-and-development:exam:d7ffe763', '3-6-training-and-development', '3.6 Training and Development', 'exam', 'mcq', 1, '{"num": "Q1", "question": "What is NOT a benefit to a golfing equipment retailer of training its sales assistants?", "options": ["To help staff give advice on which golf clubs to buy", "To increase the sales of golf umbrellas and waterproof clothing", "To motivate staff to assist customers who are trying on golf shoes", "To reduce the time it takes to make golf bags and golf trolleys"], "hint": "Think carefully about what a retailer does vs. what a manufacturer does.", "starter": "The answer is D because a retailer sells products — it does not..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D</h5><p><strong>Why D is correct:</strong> A retailer sells golf products — it does not manufacture them. Training sales assistants would not reduce manufacturing time because retail staff have no role in production.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Wrong:</strong> Helping staff give advice on products IS a genuine benefit of training retail staff — it improves the quality of customer service.</li><li><strong>B — Wrong:</strong> Better-trained staff can upsell related products (umbrellas, clothing), increasing revenue — this IS a benefit.</li><li><strong>C — Wrong:</strong> Training can motivate staff and improve their engagement with customers — this IS a benefit.</li></ul></div>", "modelAnswer": "D — To reduce the time it takes to make golf bags and golf trolleys. A retailer sells products; it does not manufacture them, so training sales assistants has no impact on production time."}'::jsonb),
('3-6-training-and-development:exam:1cc408fa', '3-6-training-and-development', '3.6 Training and Development', 'exam', 'mcq', 1, '{"num": "Q4", "question": "Which one of the following is a disadvantage of using on-the-job training to train three new sales assistants?", "options": ["Likely to be more expensive than sending the employees on a training course", "Motorists may experience lower standards of customer service", "No petrol can be sold while the training takes place", "The employees will be trained on different equipment to that at the garage"], "caseStudy": "The manager of a petrol station uses on-the-job training to train new employees.", "hint": "Think about what can go wrong when an untrained person is serving real customers during training.", "starter": "The answer is B because when a trainee is serving real customers..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B</h5><p><strong>Why B is correct:</strong> A trainee serving real customers may make mistakes or be slow, leading to lower quality customer service — motorists may experience poor service as a result.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Wrong:</strong> On-the-job training is generally cheaper than off-the-job (no external course fees or travel costs).</li><li><strong>C — Wrong:</strong> Petrol CAN still be sold during on-the-job training — the trainee is working while learning, meaning the business continues to operate.</li><li><strong>D — Wrong:</strong> On-the-job training takes place at the actual workplace using the actual equipment — so trainees ARE trained on the correct equipment.</li></ul></div>", "modelAnswer": "B — Motorists may experience lower standards of customer service because a trainee who is still learning may make mistakes or be slow when serving real customers at the petrol station."}'::jsonb),
('3-6-training-and-development:exam:059b1e4c', '3-6-training-and-development', '3.6 Training and Development', 'exam', 'mcq', 1, '{"num": "Q5", "question": "Which of the following is NOT a form of staff development?", "options": ["Academic qualifications", "Apprenticeships", "Induction", "Vocational qualifications"], "hint": "Staff development is long-term. Which of these options is short-term and about introducing a new worker to the business?", "starter": "The answer is C because induction is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C</h5><p><strong>Why C is correct:</strong> Induction is a form of training — it is short-term and designed to introduce a new employee to the business and workplace. It is NOT staff development.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Wrong:</strong> Academic qualifications (e.g. degrees) ARE a form of long-term staff development.</li><li><strong>B — Wrong:</strong> Apprenticeships ARE a form of staff development — long-term programmes leading to qualifications.</li><li><strong>D — Wrong:</strong> Vocational qualifications ARE a form of staff development — job-specific long-term learning.</li></ul></div>", "modelAnswer": "C — Induction is NOT a form of staff development. It is a short-term form of training that introduces a new employee to the workplace, colleagues, and health and safety procedures — not a long-term development programme."}'::jsonb)
